        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template <typename T>
void conv1d_tiled_kernel(const T *in,
                         T *out,
                         const T *mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  const int grids = input_width / bs;
#pragma omp target teams num_teams(grids) thread_limit(bs)
  {
    T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    const int n = mask_width / 2;
#pragma omp parallel num_threads(bs)
    {
      const int tid = omp_get_thread_num();
      const int bid = omp_get_team_num();
      const int i = tid + bid * bs;

      const int halo_left = (bid - 1) * bs + tid;
      if (tid >= bs - n) {
        tile[tid - (bs - n)] = halo_left < 0 ? (T)0 : in[halo_left];
      }

      tile[n + tid] = in[bid * bs + tid];

      const int halo_right = (bid + 1) * bs + tid;
      if (tid < n) {
        tile[tid + bs + n] = halo_right >= input_width ? (T)0 : in[halo_right];
      }

#pragma omp barrier

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        s += tile[tid + j] * mask[j];
      }

      out[i] = s;
    }
  }
}

