      const int bid = omp_get_team_num();
      const int i = tid + bid * bs;

      tile[tid] = in[i];
#pragma omp barrier

      const int this_tile_start = bid * bs;
      const int next_tile_start = (bid + 1) * bs;
      const int start = i - (mask_width / 2);

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        const int in_index = start + j;
