#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define OMP_CHECK(x) do { \
    int err = (x); \
    if (err != 0) { \
        printf("OpenMP runtime error %s:%d: %d\n", __FILE__, __LINE__, err); \
        exit(1); \
    } \
} while (0)

template<typename T>
static inline void conv1d_kernel(const T *d_in,
                                 T *d_out,
                                 const T *d_mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  const int grids = input_width / bs;

  #pragma omp target teams num_teams(grids) thread_limit(bs) is_device_ptr(d_in, d_out, d_mask)
  {
    const int block = omp_get_team_num();

    #pragma omp parallel num_threads(bs)
    {
      const int thread = omp_get_thread_num();
      const int i = thread + block * bs;

      T s = 0;
      const int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (0 <= start + j && input_width > start + j) {
          s += d_in[start + j] * d_mask[j];
        }
      }
      d_out[i] = s;
    }
  }
}

template<typename T>
static inline void conv1d_tiled_kernel(const T *d_in,
                                       T *d_out,
                                       const T *d_mask,
                                       const int input_width,
                                       const int mask_width,
                                       const int bs)
{
  const int grids = input_width / bs;

  #pragma omp target teams num_teams(grids) thread_limit(bs) is_device_ptr(d_in, d_out, d_mask)
  {
    T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    const int block = omp_get_team_num();
    const int n = mask_width / 2;

    #pragma omp parallel num_threads(bs)
    {
      const int thread = omp_get_thread_num();
      const int i = thread + block * bs;

      const int halo_left = (block - 1) * bs + thread;
      if (thread >= bs - n) {
        tile[thread - (bs - n)] = halo_left < 0 ? (T)0 : d_in[halo_left];
      }

      tile[n + thread] = d_in[block * bs + thread];

      const int halo_right = (block + 1) * bs + thread;
      if (thread < n) {
        tile[thread + bs + n] = halo_right >= input_width ? (T)0 : d_in[halo_right];
      }

      #pragma omp barrier

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        s += tile[thread + j] * d_mask[j];
      }

      d_out[i] = s;
    }
  }
}

template<typename T>
static inline void conv1d_tiled_caching_kernel(const T *d_in,
                                               T *d_out,
                                               const T *d_mask,
                                               const int input_width,
                                               const int mask_width,
                                               const int bs)
{
  const int grids = input_width / bs;

  #pragma omp target teams num_teams(grids) thread_limit(bs) is_device_ptr(d_in, d_out, d_mask)
  {
    T tile[MAX_BLOCK_SIZE];
    const int block = omp_get_team_num();

    #pragma omp parallel num_threads(bs)
    {
      const int thread = omp_get_thread_num();
      const int i = thread + block * bs;

      tile[thread] = d_in[i];

      #pragma omp barrier

      const int this_tile_start = block * bs;
      const int next_tile_start = (block + 1) * bs;
      const int start = i - (mask_width / 2);

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        const int in_index = start + j;
        if (0 <= in_index && input_width > in_index) {
          if (this_tile_start <= in_index && next_tile_start > in_index) {
            s += tile[thread + j - (mask_width / 2)] * d_mask[j];
          } else {
            s += d_in[in_index] * d_mask[j];
          }
        }
      }

      d_out[i] = s;
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; input_width > i; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; mask_width > j; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  const size_t size_bytes = (size_t)input_width * sizeof(T);

  T *a = (T *)malloc(size_bytes);
  T *b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];
  for (int i = 0; MAX_MASK_WIDTH > i; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; input_width > i; i++) {
    a[i] = (T)(rand() % 256);
  }

  const int dev = omp_get_default_device();
  const int host = omp_get_initial_device();

  T *d_a = (T *)omp_target_alloc(size_bytes, dev);
  T *d_b = (T *)omp_target_alloc(size_bytes, dev);
  T *d_mask = (T *)omp_target_alloc(MAX_MASK_WIDTH * sizeof(T), dev);

  if (!d_a || !d_b || !d_mask) {
    printf("OpenMP target allocation failed\n");
    exit(1);
  }

  OMP_CHECK(omp_target_memcpy(d_a, a, size_bytes, 0, 0, dev, host));
  OMP_CHECK(omp_target_memcpy(d_mask, h_mask, mask_width * sizeof(T), 0, 0, dev, host));

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; repeat > i; i++) {
      conv1d_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; repeat > i; i++) {
      conv1d_tiled_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; repeat > i; i++) {
      conv1d_tiled_caching_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, dev);
  omp_target_free(d_b, dev);
  omp_target_free(d_mask, dev);
}

int main(int argc, char* argv[]) {
  if (3 != argc) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; MAX_MASK_WIDTH > mask_width; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <chrono>

#define MAXDISTANCE (200)

unsigned int minimum(unsigned int a, unsigned int b)
{
  return (b < a) ? b : a;
}

void floydWarshallCPUReference(unsigned int *pathDistanceMatrix,
                               unsigned int *pathMatrix, unsigned int numNodes)
{
  unsigned int distanceYtoX, distanceYtoK, distanceKtoX, indirectDistance;
  unsigned int width = numNodes;
  unsigned int yXwidth;

  for (unsigned int k = 0; k < numNodes; ++k)
  {
    for (unsigned int y = 0; y < numNodes; ++y)
    {
      yXwidth = y * numNodes;
      for (unsigned int x = 0; x < numNodes; ++x)
      {
        distanceYtoX = pathDistanceMatrix[yXwidth + x];
        distanceYtoK = pathDistanceMatrix[yXwidth + k];
        distanceKtoX = pathDistanceMatrix[k * width + x];

        indirectDistance = distanceYtoK + distanceKtoX;

        if (indirectDistance < distanceYtoX)
        {
          pathDistanceMatrix[yXwidth + x] = indirectDistance;
          pathMatrix[yXwidth + x] = k;
        }
      }
    }
  }
}

int main(int argc, char **argv)
{
  if (argc != 4)
  {
    printf("Usage: %s <number of nodes> <iterations> <block size>\n", argv[0]);
    return 1;
  }

  unsigned int numNodes = (unsigned int)atoi(argv[1]);
  unsigned int numIterations = (unsigned int)atoi(argv[2]);
  unsigned int blockSize = (unsigned int)atoi(argv[3]);

  if (numNodes % blockSize != 0)
  {
    numNodes = (numNodes / blockSize + 1) * blockSize;
  }

  unsigned int *pathMatrix = NULL;
  unsigned int *pathDistanceMatrix = NULL;
  unsigned int *verificationPathDistanceMatrix = NULL;
  unsigned int *verificationPathMatrix = NULL;
  unsigned int matrixSizeBytes;

  matrixSizeBytes = numNodes * numNodes * sizeof(unsigned int);
  pathDistanceMatrix = (unsigned int *)malloc(matrixSizeBytes);
  assert(pathDistanceMatrix != NULL);

  pathMatrix = (unsigned int *)malloc(matrixSizeBytes);
  assert(pathMatrix != NULL);

  srand(2);
  for (unsigned int i = 0; i < numNodes; i++)
    for (unsigned int j = 0; j < numNodes; j++)
    {
      int index = (int)(i * numNodes + j);
      pathDistanceMatrix[index] = (unsigned int)(rand() % (MAXDISTANCE + 1));
    }

  for (unsigned int i = 0; i < numNodes; ++i)
  {
    unsigned int iXWidth = i * numNodes;
    pathDistanceMatrix[iXWidth + i] = 0;
  }

  for (unsigned int i = 0; i < numNodes; ++i)
  {
    for (unsigned int j = 0; j < i; ++j)
    {
      pathMatrix[i * numNodes + j] = i;
      pathMatrix[j * numNodes + i] = j;
    }
    pathMatrix[i * numNodes + i] = i;
  }

  verificationPathDistanceMatrix =
      (unsigned int *)malloc(numNodes * numNodes * sizeof(int));
  assert(verificationPathDistanceMatrix != NULL);

  verificationPathMatrix =
      (unsigned int *)malloc(numNodes * numNodes * sizeof(int));
  assert(verificationPathMatrix != NULL);

  memcpy(verificationPathDistanceMatrix, pathDistanceMatrix,
         numNodes * numNodes * sizeof(int));
  memcpy(verificationPathMatrix, pathMatrix, numNodes * numNodes * sizeof(int));

  unsigned int numPasses = numNodes;

  unsigned int globalThreads[2] = {numNodes, numNodes};
  unsigned int localThreads[2] = {blockSize, blockSize};

  if ((unsigned int)(localThreads[0] * localThreads[0]) > 256)
  {
    blockSize = 16;
    localThreads[0] = blockSize;
    localThreads[1] = blockSize;
  }

  (void)globalThreads;

  unsigned int *pathBuffer = (unsigned int *)malloc(matrixSizeBytes);
  assert(pathBuffer != NULL);

  float total_time = 0.f;
  const size_t totalElems = (size_t)numNodes * (size_t)numNodes;

#pragma omp target data map(tofrom : pathDistanceMatrix[0:totalElems]) map(alloc : pathBuffer[0:totalElems])
  {
    for (unsigned int n = 0; n < numIterations; n++)
    {
#pragma omp target update to(pathDistanceMatrix[0:totalElems])

      auto start = std::chrono::steady_clock::now();

      for (unsigned int i = 0; i < numPasses; i++)
      {
        const unsigned int pass = i;
#pragma omp target teams distribute parallel for collapse(2)
        for (unsigned int yValue = 0; yValue < numNodes; ++yValue)
        {
          for (unsigned int xValue = 0; xValue < numNodes; ++xValue)
          {
            unsigned int k = pass;
            unsigned int oldWeight =
                pathDistanceMatrix[yValue * numNodes + xValue];
            unsigned int tempWeight =
                pathDistanceMatrix[yValue * numNodes + k] +
                pathDistanceMatrix[k * numNodes + xValue];

            if (tempWeight < oldWeight)
            {
              pathDistanceMatrix[yValue * numNodes + xValue] = tempWeight;
              pathBuffer[yValue * numNodes + xValue] = k;
            }
          }
        }
      }

      auto end = std::chrono::steady_clock::now();
      auto time =
          std::chrono::duration_cast<std::chrono::nanoseconds>(end - start)
              .count();
      total_time += (float)time;
    }

#pragma omp target update from(pathDistanceMatrix[0:totalElems])
  }

  printf("Average kernel execution time %f (s)\n",
         (total_time * 1e-9f) / numIterations);

  floydWarshallCPUReference(verificationPathDistanceMatrix,
                            verificationPathMatrix, numNodes);
  if (memcmp(pathDistanceMatrix, verificationPathDistanceMatrix,
             matrixSizeBytes) == 0)
  {
    printf("PASS\n");
  }
  else
  {
    printf("FAIL\n");
    if (numNodes <= 8)
    {
      for (unsigned int i = 0; i < numNodes; i++)
      {
        for (unsigned int j = 0; j < numNodes; j++)
          printf("host: %u ",
                 verificationPathDistanceMatrix[i * numNodes + j]);
        printf("\n");
      }
      for (unsigned int i = 0; i < numNodes; i++)
      {
        for (unsigned int j = 0; j < numNodes; j++)
          printf("device: %u ", pathDistanceMatrix[i * numNodes + j]);
        printf("\n");
      }
    }
  }

  free(pathDistanceMatrix);
  free(pathMatrix);
  free(pathBuffer);
  free(verificationPathDistanceMatrix);
  free(verificationPathMatrix);
  return 0;
}

