                                    pathDistanceMatrix[(size_t)k * numNodes + xValue];

          if (oldWeight > tempWeight)
          {
            pathDistanceMatrix[(size_t)yValue * numNodes + xValue] = tempWeight;
            pathBuffer[(size_t)yValue * numNodes + xValue] = k;
          }
        }
      }
    }

