  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
  std::cout << totalPairs << " of " << nAtom*maxNeighbors << " pairs within cutoff distance = "
       << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

  int dev = omp_get_default_device();
  int hostdev = omp_get_initial_device();

  POSVECTYPE* d_position = (POSVECTYPE*) omp_target_alloc(nAtom * sizeof(POSVECTYPE), dev);
  FORCEVECTYPE* d_force = (FORCEVECTYPE*) omp_target_alloc(nAtom * sizeof(FORCEVECTYPE), dev);
  int* d_neighborList = (int*) omp_target_alloc(nAtom * maxNeighbors * sizeof(int), dev);

