  omp_target_memcpy(d_neighborList, neighborList, nAtom * maxNeighbors * sizeof(int), 0, 0, dev, hostdev);

  md(d_position, d_force, d_neighborList, nAtom, maxNeighbors, lj1, lj2, cutsq);

  omp_target_memcpy(h_force, d_force, nAtom * sizeof(FORCEVECTYPE), 0, 0, hostdev, dev);

  std::cout << "Performing Correctness Check (may take several minutes)\n";

  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(h_force, position, neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  for (int j = 0; iteration > j; j++)
  {
    md(d_position, d_force, d_neighborList, nAtom, maxNeighbors, lj1, lj2, cutsq);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  omp_target_free(d_position, dev);
  omp_target_free(d_force, dev);
  omp_target_free(d_neighborList, dev);

  free(position);
  free(h_force);
  free(neighborList);

  return 0;
}

