#pragma omp end declare target

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes) {
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0ULL;

  for (i = 0; i < size; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do {
    vertice[nivel]++;
    bit_test = 0;
    bit_test |= (1 << vertice[nivel]);

    if (vertice[nivel] == size) {
      vertice[nivel] = _EMPTY_;
    } else if (MCstillLegal(vertice, nivel) && !(flag & bit_test)) {
      flag |= (1ULL << vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth) {
        prefixesHandleSol(root_prefixes, flag, vertice, initialDepth, (int)num_sol);
        num_sol++;
      } else
        continue;
    } else
      continue;

    nivel--;
    flag &= ~(1ULL << vertice[nivel]);

  } while (nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}

void nqueens(short size, int initial_depth, unsigned long long n_explorers,
             QueenRoot *root_prefixes_h, unsigned long long *vector_of_tree_size_h,
             unsigned long long *sols_h, const int repeat) {
  const int num_teams = (int)((n_explorers + _QUEENS_BLOCK_SIZE_ - 1ULL) / _QUEENS_BLOCK_SIZE_);

  printf("\n### Regular BP-DFS search. ###\n");

  auto start = std::chrono::steady_clock::now();

#pragma omp target data map(to: root_prefixes_h[0:n_explorers]) \
                        map(from: vector_of_tree_size_h[0:n_explorers], sols_h[0:n_explorers])
  {
    for (int rep = 0; rep < repeat; rep++) {
#pragma omp target teams distribute parallel for thread_limit(_QUEENS_BLOCK_SIZE_) num_teams(num_teams)
      for (long long idx = 0; idx < (long long)n_explorers; ++idx) {
